@page "/admin/users"
@rendermode InteractiveServer
@attribute [Authorize(Roles = "Admin")]
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Identity
@using sv_00291a66aa6648a2b05ac39f6aa3e757.Data
@inject UserManager<ApplicationUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p>Manage all users and their roles.</p>

@if (userList is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Email</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var user in userList)
            {
                <tr>
                    <td>@user.Email</td>
                    <td>@user.Roles</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<UserWithRoles>? userList;

    protected override async Task OnInitializedAsync()
    {
        var users = UserManager.Users.ToList();
        userList = new List<UserWithRoles>();

        foreach (var user in users)
        {
            var roles = await UserManager.GetRolesAsync(user);
            userList.Add(new UserWithRoles
            {
                Email = user.Email ?? "(no email)",
                Roles = string.Join(", ", roles)
            });
        }
    }

    private sealed class UserWithRoles
    {
        public string Email { get; set; } = "";
        public string Roles { get; set; } = "";
    }
}

